import{_ as t,o as s,c as i,ao as a}from"./chunks/framework.Cb-Je6QH.js";const g=JSON.parse('{"title":"Closing the gaps with Rust","description":"","frontmatter":{},"headers":[],"relativePath":"rust_gaps.md","filePath":"rust_gaps.md","lastUpdated":null}'),n={name:"rust_gaps.md"};function o(l,e,r,d,h,c){return s(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="Closing-the-gaps-with-Rust" tabindex="-1">Closing the gaps with Rust <a class="header-anchor" href="#Closing-the-gaps-with-Rust" aria-label="Permalink to &quot;Closing the gaps with Rust {#Closing-the-gaps-with-Rust}&quot;">​</a></h1><p>Rust makes idiomatic code reliably fast: the compiler errors (or the type system guarantees) where Julia stays silent. StrictMode set out to make Julia <em>as predictable to optimize</em> — and dogfooding a SIMD FFT located exactly three gaps. Here is each gap and the feature that closes it.</p><h2 id="1.-The-time-tax-—-closed" tabindex="-1">1. The time tax — <em>closed</em> <a class="header-anchor" href="#1.-The-time-tax-—-closed" aria-label="Permalink to &quot;1. The time tax — _closed_ {#1.-The-time-tax-—-closed}&quot;">​</a></h2><p>Rust&#39;s guarantees are free; StrictMode&#39;s used to cost an AllocCheck pass per method (a whole-package sweep once blew a 10-minute timeout). Now:</p><ul><li><p><strong><code>:fast</code> mode</strong> is a value-free, inference-only triage of <em>all</em> properties — allocation, boxing, type-stability — built on <code>code_typed</code> IR + <code>Base.infer_effects</code>. It needs <strong>no AllocCheck/JET backend</strong> and runs <strong>~10× cheaper per method</strong> than <code>:full</code>. <code>:full</code> remains the rigorous AllocCheck proof for CI.</p></li><li><p>An <strong>incremental cache</strong> keys findings on <code>(method, world, signature, mode)</code>, so re-running <code>audit</code> after a one-method edit only re-analyzes that method — near-instant.</p></li><li><p><code>:fast</code> sweeps run <strong>across threads</strong>.</p></li></ul><p>A whole-module re-check on every edit is now affordable. See <a href="./getting_started">Getting Started</a>.</p><h2 id="2.-Opt-in,-not-pervasive-—-closed" tabindex="-1">2. Opt-in, not pervasive — <em>closed</em> <a class="header-anchor" href="#2.-Opt-in,-not-pervasive-—-closed" aria-label="Permalink to &quot;2. Opt-in, not pervasive — _closed_ {#2.-Opt-in,-not-pervasive-—-closed}&quot;">​</a></h2><p>Rust disciplines <em>every</em> function by default; you opt out of safety, not into it. StrictMode now mirrors that:</p><ul><li><p><strong><code>@strict module … end</code></strong> — one declaration makes every function in the module hot (checked) automatically. No per-function annotations.</p></li><li><p><strong><code>@strict_exempt</code></strong> — the rare cold / by-design-allocating helper opts <em>out</em> at its definition.</p></li><li><p>The whole-module load check uses the cheap <code>:fast</code> path, and <code>audit</code> reports only declared-hot violations — so it&#39;s quiet by default. See <a href="./automating">Automating checks</a>.</p></li></ul><h2 id="3.-Scheduling-and-vectorization-—-surfaced,-not-controlled" tabindex="-1">3. Scheduling &amp; vectorization — <em>surfaced, not controlled</em> <a class="header-anchor" href="#3.-Scheduling-and-vectorization-—-surfaced,-not-controlled" aria-label="Permalink to &quot;3. Scheduling &amp; vectorization — _surfaced, not controlled_ {#3.-Scheduling-and-vectorization-—-surfaced,-not-controlled}&quot;">​</a></h2><p>The residual gap is instruction scheduling and vectorization, which live <strong>below</strong> user code. StrictMode <strong>cannot</strong> match rustc&#39;s instruction scheduler — that is an explicit non-goal, and this section is honest about the ceiling. What it <em>can</em> do is make the layer visible and reachable:</p><ul><li><p><strong><code>@assert_vectorized f(args...)</code></strong> — best-effort: did the loop emit SIMD vector ops (<code>&lt;N x …&gt;</code> in the LLVM IR)? Loud failure if it didn&#39;t.</p></li><li><p><strong><code>@assert_effects f(args...) (:nothrow, :effect_free, …)</code></strong> — verify the compiler&#39;s inferred effects (<code>Base.infer_effects</code>); the <em>verify</em> side of <code>Base.@assume_effects</code>.</p></li><li><p><strong><a href="/StrictMode.jl/dev/api#StrictMode.descend"><code>descend</code></a><code>(f, types)</code></strong> — drop into <a href="https://github.com/JuliaDebug/Cthulhu.jl" target="_blank" rel="noreferrer">Cthulhu</a> to <em>see</em> inlining, effects, type-stability, and the LLVM/native code (optional weak dependency).</p></li></ul><h3 id="The-ceiling,-and-the-escape-hatch" tabindex="-1">The ceiling, and the escape hatch <a class="header-anchor" href="#The-ceiling,-and-the-escape-hatch" aria-label="Permalink to &quot;The ceiling, and the escape hatch {#The-ceiling,-and-the-escape-hatch}&quot;">​</a></h3><p>When the compiler&#39;s scheduling decisions are the bottleneck, the levers — in increasing order of control — are:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Lever</th><th style="text-align:right;">What it influences</th></tr></thead><tbody><tr><td style="text-align:right;"><code>@inbounds</code>, <code>@simd ivdep</code></td><td style="text-align:right;">removes bounds checks / asserts no loop-carried deps → enables vectorization</td></tr><tr><td style="text-align:right;"><code>Base.@assume_effects</code></td><td style="text-align:right;">declares effects (<code>:nothrow</code>, <code>:consistent</code>, …) the compiler can build on</td></tr><tr><td style="text-align:right;"><code>Base.llvmcall</code></td><td style="text-align:right;">hand-written LLVM IR — the final escape hatch for the hottest kernels</td></tr></tbody></table><p>StrictMode does not wrap these (they are Base); its contribution is to keep your escape-hatch kernels <strong>verifiable</strong> — assert your <code>llvmcall</code> kernel is still allocation-free, and <code>descend</code> into it to confirm the codegen:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># hand-written IR for a hot kernel…</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">addll</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Int64</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Int64</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Base</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">llvmcall</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;%z = add i64 %0, %1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ret i64 %z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, Int64, Tuple{Int64,Int64}, x, y)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@assert_noalloc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> addll</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># …still on the fast path</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">descend</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(addll, (Int64, Int64))  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># …and see exactly what it compiled to</span></span></code></pre></div><p><strong>The honest summary:</strong> Julia + StrictMode is now as easy to optimize as Rust for <em>everything except raw instruction scheduling</em> — which remains rustc&#39;s domain, reachable here only through hand-written IR.</p>`,18)])])}const u=t(n,[["render",o]]);export{g as __pageData,u as default};
